import React from "react";
import { useNavigate } from "react-router-dom";
import SimpleNavbar from "./SimpleNavbar";
import SimpleFooter from "./SimpleFooter";

function Login() {
  const navigate = useNavigate();

  return (
    <div style={styles.container}>

      {/* ✅ Navbar */}
      <SimpleNavbar />

      {/* Login Card */}
      <div style={styles.main}>
        <div style={styles.card}>
          <h2 style={styles.title}>Login</h2>

          <input
            type="text"
            placeholder="Email"
            style={styles.input}
          />

          <input
            type="password"
            placeholder="Password"
            style={styles.input}
          />

          <button style={styles.button}>Login</button>

          <p style={styles.text}>
            Don't have an account?{" "}
            <span
              style={styles.link}
              onClick={() => navigate("/register")}
            >
              Register
            </span>
          </p>
        </div>
      </div>

      {/* ✅ Footer */}
      <SimpleFooter />

    </div>
  );
}

export default Login;

const styles = {
  container: {
    fontFamily: "Segoe UI, sans-serif",
    height: "100vh",
    display: "flex",
    flexDirection: "column",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    background: "#f3f6fb",
  },

  card: {
    backgroundColor: "white",
    padding: "35px",
    borderRadius: "16px",
    width: "320px",
    textAlign: "center",
    boxShadow: "0 12px 30px rgba(0,0,0,0.08)",
    border: "1px solid #eef2f7",
  },

  title: {
    marginBottom: "20px",
    fontSize: "22px",
    fontWeight: "600",
    color: "#1f2937",
  },

  input: {
    width: "100%",
    padding: "12px",
    margin: "10px 0",
    borderRadius: "8px",
    border: "1px solid #e5e7eb",
  },

  button: {
    width: "100%",
    padding: "12px",
    background: "linear-gradient(135deg, #2563EB, #1E40AF)",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
    marginTop: "10px",
    fontWeight: "600",
  },

  text: {
    marginTop: "15px",
    fontSize: "14px",
  },

  link: {
    color: "#2563EB",
    fontWeight: "600",
    cursor: "pointer",
  },
};
